// Create Summary - Aggregate all articles
const allItems = $input.all();

console.log('📦 Total items received:', allItems.length);

// Group by source
const bySource = {};

allItems.forEach(item => {
  const article = item.json.original_article || item.json;
  const source = article.crawler_source || 'unknown';

  if (!bySource[source]) {
    bySource[source] = {
      source_id: source,
      source_name: article.crawler_source_name || article.source || source,
      total: 0,
      successful: 0,
      failed: 0
    };
  }

  bySource[source].total++;

  if (item.json.error) {
    bySource[source].failed++;
  } else {
    bySource[source].successful++;
  }
});

const summary = {
  run_id: allItems[0]?.json.run_id || allItems[0]?.json.original_article?.run_id || Date.now(),
  completed_at: new Date().toISOString(),
  total_sources: Object.keys(bySource).length,
  total_articles: allItems.length,
  successful: allItems.filter(i => !i.json.error).length,
  failed: allItems.filter(i => i.json.error).length,
  by_source: Object.values(bySource)
};

console.log('📊 Final Summary:', JSON.stringify(summary, null, 2));

return [{ json: summary }];

// Prepare Summary Log - FOR OPENSEARCH
const summary = $('Create Summary1').first().json;

const logData = {
  request_id: summary.run_id + '-summary',
  source: 'news_crawler',
  endpoint: '/crawl/summary',
  http_method: 'POST',
  status: summary.failed > 0 ? 'partial_success' : 'success',
  http_code: 200,
  created_at: summary.completed_at,
  triggered_by: 'n8n',
  payload_excerpt: {
    total_sources: summary.total_sources,
    total_articles: summary.total_articles,
    successful: summary.successful,
    failed: summary.failed,
    by_source: summary.by_source
  }
};

return [{
  json: {
    ...summary,
    log_data: logData
  }
}];

// Prepare Article Log - FOR OPENSEARCH
const response = $json;
const article = $input.item.json || $json;

const source = article.crawler_source || 'unknown';
const articleId = (article.id || 'no-id').substring(0, 80);

const logData = {
  request_id: article.run_id + '-' + articleId.substring(0, 20),
  source: 'news_crawler',
  endpoint: '/crawl/' + source,
  http_method: 'GET',
  status: response.error ? 'failed' : 'success',
  http_code: response.error ? 500 : 200,
  created_at: new Date().toISOString(),
  error_type: response.error ? 'INDEX_ERROR' : null,
  error_message: response.error ? String(response.error) : null,
  triggered_by: 'n8n',
  payload_excerpt: {
    article_id: articleId,
    source: source,
    title: (article.title || '').substring(0, 100)
  }
};

return [{
  json: {
    ...response,
    original_article: article,
    log_data: logData
  }
}];

// Parse Articles - RUN ONCE FOR EACH ITEM
const articles = $json.data;

// Error handling
if (!articles) {
  console.log('⚠️ Empty response from crawler');
  throw new Error('Empty response from crawler');
}

let parsedArticles;
if (typeof articles === 'string') {
  if (articles.trim() === '' || articles === '[]') {
    throw new Error('Empty response from crawler');
  }
  try {
    parsedArticles = JSON.parse(articles);
  } catch (e) {
    console.log('❌ JSON parse error:', e.message);
    throw new Error('JSON parse failed: ' + e.message);
  }
} else {
  parsedArticles = articles;
}

if (!Array.isArray(parsedArticles) || parsedArticles.length === 0) {
  console.log('⚠️ No articles found');
  throw new Error('No articles found for this source');
}

// Source bilgisini al
const allSourceInputs = $('Define All Sources').all();
const sourceInfo = allSourceInputs[$itemIndex].json;

console.log('🔍 Processing Source #' + $itemIndex + ':', sourceInfo.id, '- Articles:', parsedArticles.length);

const runId = sourceInfo.run_id || Date.now();
const retrievedAt = new Date().toISOString();

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

const processedArticles = parsedArticles.map((article, articleIndex) => {
  const originalUrl = article.url || article.link || article.id;

  let uniqueString;
  if (originalUrl && (originalUrl.startsWith('http://') || originalUrl.startsWith('https://'))) {
    uniqueString = originalUrl.toLowerCase().trim();
  } else {
    const title = (article.title || '').toLowerCase().trim();
    const date = article.published_date || article.date || '';
    uniqueString = `${sourceInfo.id}-${title}-${date}`;
  }

  const hash = simpleHash(uniqueString);
  const cleanId = `${sourceInfo.id}-${hash}`;

  return {
    ...article,
    _opensearch_id: cleanId,
    url: originalUrl,
    id: originalUrl,
    crawler_source: sourceInfo.id,
    crawler_source_name: sourceInfo.name,
    language: sourceInfo.language,  // ✅ Language added here
    run_id: runId,
    article_index: articleIndex,
    total_for_this_source: parsedArticles.length,
    retrieved_at: retrievedAt
  };
});

// ✅ TEK OBJE DÖNDÜR (Run Once for Each Item kuralı)
return {
  json: {
    source: sourceInfo.id,
    language: sourceInfo.language,  // ✅ Language added here too
    articles: processedArticles  // Array içeride
  }
};

// Define all news sources (only functional endpoints)
