const runId = Date.now();
return sources.map(source => ({
  json: {
    ...source,
    run_id: runId,
    started_at: new Date().toISOString()
  },
  pairedItem: { item: 0 }
}));

// Split Articles - RUN ONCE FOR ALL ITEMS
const allItems = $input.all();

console.log('📦 Total sources processed:', allItems.length);

const result = [];

allItems.forEach((item, sourceIndex) => {
  console.log('Processing source', sourceIndex, ':', item.json.source);

  const articles = item.json.articles;

  if (!articles) {
    console.log('⚠️ No articles field found in item', sourceIndex);
    return;
  }

  if (!Array.isArray(articles)) {
    console.log('⚠️ Articles is not an array in item', sourceIndex);
    return;
  }

  console.log('  → Found', articles.length, 'articles');

  articles.forEach((article, idx) => {
    // ✅ TABLOYA UYGUN FIELD MAPPING
    result.push({ 
      json: {
        id: article._opensearch_id,                          // Keyword - unique ID
        url: article.url,
        title: article.title || '',                          // Text
        body: article.body || article.description || '',     // Text
        language: article.language || 'en',                  // Keyword - ISO code
        source: article.crawler_source,                      // Keyword - Publisher
        published_at: article.published_date || article.date || article.retrieved_at, // Date - ISO-8601

        // Extra metadata (opsiyonel)
        _metadata: {
          crawler_source_name: article.crawler_source_name,
          article_index: article.article_index,
          total_for_this_source: article.total_for_this_source,
          run_id: article.run_id,
          original_url: article.url
        }
      }
    });
  });
});

console.log('✅ Total articles to index:', result.length);

return result;

// Prepare Error Log for Crawler API
// When error occurs, the input is the error object and source data is in the same item
const inputData = $input.first().json;

// Extract source info - it's in the same object when error occurs
const sourceInfo = {
  id: inputData.id || 'unknown',
  name: inputData.name || 'unknown',
  endpoint: inputData.endpoint || 'unknown',
  run_id: inputData.run_id || Date.now()
};

const error = inputData.error || {};

const logData = {
  request_id: sourceInfo.run_id + '-' + sourceInfo.id + '-error',
  source: 'news_crawler',
  endpoint: '/crawl/' + sourceInfo.id,
  http_method: 'GET',
  status: 'failed',
  http_code: error.status || 500,
  created_at: new Date().toISOString(),
  error_type: error.code || error.name || 'API_ERROR',
  error_message: error.message || String(error),
  attempt: 1,
  triggered_by: 'n8n',
  payload_excerpt: {
    source_id: sourceInfo.id,
    source_name: sourceInfo.name,
    endpoint: sourceInfo.endpoint
  }
};

return [{
  json: {
    log_data: logData,
    error: error,
    source_info: sourceInfo
  }
}];

// Prepare Error Log for Parse Articles
const error = $json;
const sourceData = $input.item.json;

const logData = {
  request_id: (sourceData.run_id || Date.now()) + '-parse-error',
  source: 'news_crawler',
  endpoint: '/parse/' + (sourceData.source || 'unknown'),
  http_method: 'POST',
  status: 'failed',
  http_code: 500,
  created_at: new Date().toISOString(),
  error_type: 'PARSE_ERROR',
  error_message: error.message || String(error),
  attempt: 1,
  triggered_by: 'n8n',
  payload_excerpt: {
    source: sourceData.source || 'unknown',
    data_received: typeof sourceData.data === 'string' ? sourceData.data.substring(0, 200) : 'object'
  }
};

return [{
  json: {
    log_data: logData,
    error: error
  }
}];

// Prepare Error Log for Index Article
const error = $json;
const article = $input.item.json;

const logData = {
  request_id: (article.run_id || Date.now()) + '-index-' + (article.id || 'unknown').substring(0, 20) + '-error',
  source: 'news_crawler',
  endpoint: '/index/' + (article.crawler_source || 'unknown'),
  http_method: 'POST',
  status: 'failed',
  http_code: error.httpCode || 500,
  created_at: new Date().toISOString(),
  error_type: 'INDEX_ERROR',
  error_message: error.message || String(error),
  attempt: 1,
  triggered_by: 'n8n',
  payload_excerpt: {
    article_id: (article.id || '').substring(0, 80),
    source: article.crawler_source || 'unknown',
    title: (article.title || '').substring(0, 100)
  }
};

return [{
  json: {
    log_data: logData,
    error: error,
    original_article: article
  }
}];

// Prepare input data
const category = $input.first().json.category || "Uncategorized";
const article = $input.first().json.article || {
  id: "test-article-" + Date.now(),
  url: "https://example.com/test",
  title: "Test Article"
};
const clusterInfo = $input.first().json.cluster_info || {};

return {
  category: category,
  article: article,
  cluster_info: clusterInfo
};

// Get data from previous nodes
const checkResult = $input.item.json;
const inputData = $node["Prepare Data"].json;

const existing = checkResult._source || {};
const newArticleId = inputData.article.id;
const category = inputData.category;
const clusterInfo = inputData.cluster_info || {};

// Get existing article_ids or create new array
let articleIds = existing.article_ids || [];

// Add new article ID if not already present
if (!articleIds.includes(newArticleId)) {
  articleIds.push(newArticleId);
}

// Prepare updated document
const updatedDoc = {
  category: category,
  article_ids: articleIds,
  article_count: articleIds.length,
  cluster_id: clusterInfo.cluster_id || existing.cluster_id || null,
  request_id: clusterInfo.request_id || existing.request_id || null,
  ingested_at: existing.ingested_at || new Date().toISOString(),
  processed_at: new Date().toISOString(),
  is_noise_cluster: clusterInfo.is_noise_cluster !== undefined ? clusterInfo.is_noise_cluster : (existing.is_noise_cluster || false),
  use_lda: clusterInfo.use_lda !== undefined ? clusterInfo.use_lda : (existing.use_lda || false),
  used_lda: clusterInfo.used_lda !== undefined ? clusterInfo.used_lda : (existing.used_lda || false),
  lda_keywords: clusterInfo.lda_keywords || existing.lda_keywords || []
};

return updatedDoc;

// Create new document for category
const inputData = $node["Prepare Data"].json;

const newArticleId = inputData.article.id;
const category = inputData.category;
const clusterInfo = inputData.cluster_info || {};

const newDoc = {
  category: category,
  article_ids: [newArticleId],
  article_count: 1,
  cluster_id: clusterInfo.cluster_id || null,
  request_id: clusterInfo.request_id || null,
  ingested_at: new Date().toISOString(),
  processed_at: new Date().toISOString(),
  is_noise_cluster: clusterInfo.is_noise_cluster || false,
  use_lda: clusterInfo.use_lda || false,
  used_lda: clusterInfo.used_lda || false,
  lda_keywords: clusterInfo.lda_keywords || []
};

return newDoc;
